DROP TABLE IF EXISTS cheat_logs;

CREATE TABLE `cheat_logs` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `course_code` varchar(255) NOT NULL,
  `status` varchar(255) NOT NULL,
  `switches` int(11) DEFAULT 0,
  PRIMARY KEY (`id`),
  UNIQUE KEY `user_id` (`user_id`,`course_code`),
  UNIQUE KEY `idx_user_course` (`user_id`,`course_code`)
) ENGINE=InnoDB AUTO_INCREMENT=50 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS class_courses;

CREATE TABLE `class_courses` (
  `class_course_id` int(11) NOT NULL AUTO_INCREMENT,
  `class_id` int(11) DEFAULT NULL,
  `course_id` int(11) DEFAULT NULL,
  `opening_date` datetime DEFAULT NULL,
  `deadline` datetime DEFAULT NULL,
  `selected_subtopic` varchar(255) DEFAULT NULL,
  `easy_limit` int(11) DEFAULT 0,
  `medium_limit` int(11) DEFAULT 0,
  `hard_limit` int(11) DEFAULT 0,
  `show_correct_after_three` tinyint(1) DEFAULT 0,
  `show_right_wrong_feedback` tinyint(1) DEFAULT 1,
  PRIMARY KEY (`class_course_id`),
  UNIQUE KEY `class_id` (`class_id`,`course_id`)
) ENGINE=InnoDB AUTO_INCREMENT=132 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS class_enrollments;

CREATE TABLE `class_enrollments` (
  `enrollment_id` int(11) NOT NULL AUTO_INCREMENT,
  `class_id` int(11) DEFAULT NULL,
  `user_id` int(11) DEFAULT NULL,
  `enrollment_date` datetime DEFAULT current_timestamp(),
  `is_approved` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`enrollment_id`),
  KEY `class_enrollments_user_fk` (`user_id`),
  CONSTRAINT `class_enrollments_user_fk` FOREIGN KEY (`user_id`) REFERENCES `users_new` (`user_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS classes;

CREATE TABLE `classes` (
  `class_id` int(11) NOT NULL AUTO_INCREMENT,
  `class_name` varchar(100) NOT NULL,
  `class_code` varchar(10) NOT NULL,
  `faculty_id` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `status` varchar(20) DEFAULT 'active',
  PRIMARY KEY (`class_id`),
  UNIQUE KEY `class_code` (`class_code`),
  KEY `faculty_id` (`faculty_id`),
  CONSTRAINT `classes_ibfk_1` FOREIGN KEY (`faculty_id`) REFERENCES `users_new` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=54 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS courses;

CREATE TABLE `courses` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `course_code` varchar(10) NOT NULL,
  `course_name` varchar(100) NOT NULL,
  `prog_id` int(11) NOT NULL,
  `opening_date` datetime DEFAULT NULL,
  `deadline` datetime DEFAULT NULL,
  `easy_limit` int(11) DEFAULT NULL,
  `medium_limit` int(11) DEFAULT NULL,
  `hard_limit` int(11) DEFAULT NULL,
  `selected_subtopic` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `prog_id` (`prog_id`),
  CONSTRAINT `courses_ibfk_1` FOREIGN KEY (`prog_id`) REFERENCES `programs` (`prog_id`)
) ENGINE=InnoDB AUTO_INCREMENT=62 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


  

DROP TABLE IF EXISTS databank_logs;

CREATE TABLE `databank_logs` (
  `log_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) DEFAULT NULL,
  `course_code` varchar(50) DEFAULT NULL,
  `questions_count` int(11) DEFAULT NULL,
  `category_breakdown` varchar(255) DEFAULT NULL,
  `timestamp` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`log_id`)
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS exam;

CREATE TABLE `exam` (
  `exam_id` int(11) NOT NULL AUTO_INCREMENT,
  `book_title` varchar(255) NOT NULL,
  `volume` varchar(255) NOT NULL,
  `author` varchar(255) NOT NULL,
  `published_date` varchar(255) NOT NULL,
  `course_code` varchar(10) NOT NULL,
  `course_name` varchar(50) NOT NULL,
  `subtopic` varchar(255) NOT NULL,
  `questions` varchar(1000) NOT NULL,
  `subquestions` varchar(1000) NOT NULL,
  `question_img` longtext DEFAULT NULL,
  `ch_1` varchar(100) NOT NULL,
  `ch_1_img` longtext NOT NULL,
  `ch_2` varchar(100) NOT NULL,
  `ch_2_img` longtext DEFAULT NULL,
  `ch_3` varchar(100) NOT NULL,
  `ch_3_img` longtext DEFAULT NULL,
  `ch_4` varchar(100) NOT NULL,
  `ch_4_img` longtext DEFAULT NULL,
  `anskey` varchar(100) NOT NULL,
  `category` varchar(50) NOT NULL,
  `points` int(11) DEFAULT 1,
  `time_limit` int(11) DEFAULT NULL,
  PRIMARY KEY (`exam_id`)
) ENGINE=InnoDB AUTO_INCREMENT=9366 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS flagged_questions;

CREATE TABLE `flagged_questions` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) DEFAULT NULL,
  `exam_id` int(11) DEFAULT NULL,
  `course_code` varchar(50) DEFAULT NULL,
  `class_id` int(11) DEFAULT NULL,
  `report_date` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS programs;

CREATE TABLE `programs` (
  `prog_id` int(11) NOT NULL AUTO_INCREMENT,
  `program_code` varchar(10) NOT NULL,
  `program_name` varchar(100) NOT NULL,
  `program_logo` varchar(255) DEFAULT 'default_logo.png',
  PRIMARY KEY (`prog_id`)
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS question_exclusions;

CREATE TABLE `question_exclusions` (
  `exclusion_id` int(11) NOT NULL AUTO_INCREMENT,
  `class_id` int(11) DEFAULT NULL,
  `course_code` varchar(50) DEFAULT NULL,
  `exam_id` int(11) DEFAULT NULL,
  `excluded_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`exclusion_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS student_attempts;

CREATE TABLE `student_attempts` (
  `attempt_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) DEFAULT NULL,
  `course_code` varchar(50) NOT NULL,
  `class_id` int(11) DEFAULT NULL,
  `exam_id` int(11) NOT NULL,
  `selected_choice` varchar(10) DEFAULT NULL,
  `is_correct` tinyint(1) DEFAULT NULL,
  `date_taken` timestamp NOT NULL DEFAULT current_timestamp(),
  `trial_number` int(11) DEFAULT 1,
  `attempt_group_id` varchar(50) DEFAULT NULL,
  `flagged_no_answer` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`attempt_id`),
  KEY `student_attempts_ibfk_1` (`user_id`),
  CONSTRAINT `student_attempts_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users_new` (`user_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1785 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS system_settings;

CREATE TABLE `system_settings` (
  `setting_key` varchar(50) NOT NULL,
  `setting_value` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`setting_key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS user_logs;

CREATE TABLE `user_logs` (
  `log_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) DEFAULT NULL,
  `user_type` varchar(50) DEFAULT NULL,
  `action` varchar(255) DEFAULT NULL,
  `timestamp` datetime DEFAULT current_timestamp(),
  `first_name` varchar(100) DEFAULT NULL,
  `last_name` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`log_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3148 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




DROP TABLE IF EXISTS users_new;

CREATE TABLE `users_new` (
  `user_id` int(11) NOT NULL AUTO_INCREMENT,
  `first_name` varchar(100) DEFAULT NULL,
  `last_name` varchar(100) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `password` varchar(255) DEFAULT NULL,
  `role` enum('student','faculty','admin','superadmin') NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




