INSERT INTO exam VALUES("1816","Engineering Mathematics","Volume 1","Venancio I. Besavilla, Jr.","1997","CE2","Algebra","Venn Diagram","Prior to the last IBP electrions, a survet was conducted in a certain barangay in Metro Manila to find out which of the three political parties they like best. The results indicated that 320 liked KBL, 250 liked LABAN and 180 liked INDEPENDENTS. But of there, 160 like both KBL and LABAN, 100 liked both LABAN and INDEPENDENTS and 70 liked both KBL and INDEPENDENTS. Only 30 said they liked alll three parties and none admited that they did not like any party. How many voters are there in the barangay?","","","450","","400","","500","","475","","ch_1","Hard","1","0");
